    : d =&gt; formatIcelandic(d, {digits: 0, suffix: cfg.suffix || ""});

  const hlineMarks = (cfg.hlines || []).map(v =&gt;
    Plot.ruleY([v], {stroke: "#999", strokeDasharray: "4,4", strokeOpacity: 0.5})
  );

  const yDomain = cfg.yLim || undefined;

  return Plot.plot({
